int getMiddleElement(Node* head){
    if (head == NULL) return -1;

    Node* slow = head;
    Node* fast = head;

    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;
        fast = fast->next->next;
    }

    return slow->val;
}

code.C:
typedef struct Node NODE;
NODE *getMiddleElement(NODE *head){
if (!head || !head->next) {
        return head; // Return head if the list is empty or has one node
    }

    NODE *slow = head;
    NODE *fast = head;

    // Move fast pointer two steps and slow pointer one step
    while (fast && fast->next) {
        slow = slow->next;       // Move slow pointer one step
        fast = fast->next->next; // Move fast pointer two steps
    }

    return slow; 
}

code.Java:
static int getMiddleElement(Node head) {
    if (head == null) {
        return -1; // Return -1 for empty list
    }

    Node slow = head;
    Node fast = head;

    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
    }

    return slow.val;
}

